/**
 * WebSocket Heartbeat Handler
 * Manages ping/pong protocol at application layer to detect stale connections
 * Complements Socket.io's transport-level keepalive
 */

import { Socket } from 'socket.io';

import { logger } from '../../utils/logger';
import { createHeartbeat, HeartbeatMessage } from '../schemas/message-envelope';

export interface HeartbeatConfig {
  intervalMs: number; // Send ping every N ms
  timeoutMs: number; // Expect pong within N ms
  maxMissedPongs: number; // Close connection after N missed pongs
}

export const DEFAULT_HEARTBEAT_CONFIG: HeartbeatConfig = {
  intervalMs: 30000, // 30 seconds
  timeoutMs: 5000, // 5 second response window
  maxMissedPongs: 3, // Close after 3 missed
};

interface HeartbeatState {
  lastPingSent?: Date;
  lastPongReceived?: Date;
  missedPongs: number;
  isActive: boolean;
  timeoutHandle?: NodeJS.Timeout;
  intervalHandle?: NodeJS.Timeout;
}

/**
 * Attach heartbeat protocol to a Socket
 */
export function attachHeartbeat(
  socket: Socket,
  config: Partial<HeartbeatConfig> = {}
): HeartbeatState {
  const finalConfig = { ...DEFAULT_HEARTBEAT_CONFIG, ...config };
  const state: HeartbeatState = {
    missedPongs: 0,
    isActive: true,
  };

  // Listen for pong responses
  socket.on('pong', (message: HeartbeatMessage) => {
    if (state.timeoutHandle) {
      clearTimeout(state.timeoutHandle);
      state.timeoutHandle = undefined;
    }

    state.lastPongReceived = new Date();
    state.missedPongs = 0;

    logger.debug(
      `Heartbeat pong received from ${socket.id} (latency: ${new Date().getTime() - new Date(message.timestamp).getTime()}ms)`
    );
  });

  // Handle heartbeat timeout (no pong received in time)
  socket.on('ping-timeout', () => {
    state.missedPongs++;
    logger.warn(
      `Heartbeat timeout for ${socket.id} (${state.missedPongs}/${finalConfig.maxMissedPongs})`
    );

    if (state.missedPongs >= finalConfig.maxMissedPongs) {
      logger.error(`Max missed pongs reached for ${socket.id}, disconnecting`);
      socket.disconnect(true);
      state.isActive = false;
    }
  });

  // Start sending pings
  state.intervalHandle = setInterval(() => {
    if (!state.isActive || !socket.connected) {
      return;
    }

    const heartbeat = createHeartbeat('ping');
    state.lastPingSent = new Date(heartbeat.timestamp);

    socket.emit('ping', heartbeat);

    // Set timeout waiting for pong
    state.timeoutHandle = setTimeout(() => {
      socket.emit('ping-timeout');
    }, finalConfig.timeoutMs);
  }, finalConfig.intervalMs);

  return state;
}

/**
 * Detach heartbeat protocol from a Socket
 */
export function detachHeartbeat(socket: Socket, state: HeartbeatState): void {
  state.isActive = false;

  if (state.intervalHandle) {
    clearInterval(state.intervalHandle);
  }

  if (state.timeoutHandle) {
    clearTimeout(state.timeoutHandle);
  }

  socket.removeAllListeners('pong');
  socket.removeAllListeners('ping-timeout');
}

/**
 * Get current heartbeat statistics for a socket
 */
export function getHeartbeatStats(state: HeartbeatState): {
  isActive: boolean;
  lastPingSent?: string;
  lastPongReceived?: string;
  missedPongs: number;
  estimatedLatencyMs?: number;
} {
  return {
    isActive: state.isActive,
    lastPingSent: state.lastPingSent?.toISOString(),
    lastPongReceived: state.lastPongReceived?.toISOString(),
    missedPongs: state.missedPongs,
    estimatedLatencyMs:
      state.lastPingSent && state.lastPongReceived
        ? new Date(state.lastPongReceived).getTime() - new Date(state.lastPingSent).getTime()
        : undefined,
  };
}
